export const totalLibraryWords = libraryGuides.reduce(
  (total, guide) =>
    total +
    guide.sections.reduce(
      (sectionTotal, section) =>
        sectionTotal +
        countWords(section.heading) +
        section.paragraphs.reduce(
          (paragraphTotal, paragraph) => paragraphTotal + countWords(paragraph),
          0,
        ),
      0,
    ),
  0,
);
